use crate::registry::GainModelDefinition;
use crate::GainBackendKind;
use anyhow::Result;
use block_core::param::{
    float_parameter, required_f32, ModelParameterSchema, ParameterSet, ParameterUnit,
};
use block_core::{AudioChannelLayout, BlockProcessor, ModelAudioMode, MonoProcessor, StereoProcessor};

pub const MODEL_ID: &str = "lv2_freakclip";
pub const DISPLAY_NAME: &str = "Freakclip";
const BRAND: &str = "freaked";

const PLUGIN_URI: &str = "http://faust-lv2.googlecode.com/Freakclip";
const PLUGIN_DIR: &str = "Freakclip";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "Freakclip.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "Freakclip.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "Freakclip.dll";

// Port indices (from TTL)
const PORT_CTRL_CLIP: usize = 0;
const PORT_CTRL_DELAY: usize = 1;
const PORT_CTRL_DRIVE: usize = 2;
const PORT_AUDIO_IN_IN0: usize = 3;
const PORT_AUDIO_OUT_OUT0: usize = 4;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_GAIN.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::DualMono,
        parameters: vec![
            float_parameter("clip", "Clip", None, Some(1.0), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("delay", "Delay", None, Some(0.996), 0.0, 0.999, 0.001, ParameterUnit::None),
            float_parameter("drive", "Drive", None, Some(1.0), 1.0, 9.9, 0.01, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let clip = required_f32(params, "clip").map_err(anyhow::Error::msg)?;
    let delay = required_f32(params, "delay").map_err(anyhow::Error::msg)?;
    let drive = required_f32(params, "drive").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_CLIP, clip),
        (PORT_CTRL_DELAY, delay),
        (PORT_CTRL_DRIVE, drive),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN0], &[PORT_AUDIO_OUT_OUT0], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN0], &[PORT_AUDIO_OUT_OUT0], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN0], &[PORT_AUDIO_OUT_OUT0], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

